class DeepLinkHandler extends StatefulWidget {
  final Widget child;
  
  DeepLinkHandler({Key? key, required this.child}) : super(key: key);

  @override
  _DeepLinkHandlerState createState() => _DeepLinkHandlerState();
}

class _DeepLinkHandlerState extends State<DeepLinkHandler> {
  String? _initialLink;

  @override
  void initState() {
    super.initState();
    _initUniLinks();
  }

  void _initUniLinks() async {
    try {
      _initialLink = await getInitialLink();
      if (_initialLink != null) {
        _handleLink(_initialLink!);
      }
      
      // Listen for incoming links
      uriLinkStream.listen((Uri? uri) {
        if (uri != null) {
          _handleLink(uri.toString());
        }
      }, onError: (err) {
        print('Error listening to links: $err');
      });
    } catch (e) {
      print('Error initializing uni_links: $e');
    }
  }

  void _handleLink(String link) {
    final uri = Uri.parse(link);
    final path = uri.path;
    final params = uri.queryParameters;
    
    WidgetsBinding.instance.addPostFrameCallback((_) {
      final navigator = Navigator.of(context);
      
      if (path.startsWith('/profile')) {
        final userId = path.split('/')[3];
        navigator.pushNamed('/profile', arguments: {'userId': userId});
      } else if (path.startsWith('/payment')) {
        final action = path.split('/')[3];
        if (action == 'confirm') {
          navigator.pushNamed('/payment/confirm', arguments: params);
        }
      }
    });
  }

  @override
  Widget build(BuildContext context) {
    return widget.child;
  }
}

class AppRouter {
  static Route<dynamic> generateRoute(RouteSettings settings) {
    switch (settings.name) {
      case '/profile':
        return MaterialPageRoute(
          builder: (_) => ProfileScreen(userId: settings.arguments?['userId']),
        );
      case '/payment/confirm':
        return MaterialPageRoute(
          builder: (_) => PaymentConfirmationScreen(arguments: settings.arguments),
        );
      default:
        return MaterialPageRoute(builder: (_) => SplashScreen());
    }
  }
}

